"""Runtime commands for GreenNode AgentBase CLI."""

import asyncio
import json
import logging
from typing import Any, Dict, List, Optional

import click
from rich.console import Console
from rich.table import Table

from . import CONTEXT_SETTINGS
from .outbound_auth import CANCELLED, prompt_field, prompt_if_missing


def _ensure_not_cancelled(value, _name: str = "") -> None:
    if value is CANCELLED:
        console.print("Cancelled.")
        raise SystemExit(0)
from ..core.config import get_config_value
from ..core.logging import configure_logger
from ..core import run_async_with_cleanup
from ..identity.credentials import IAMCredentials
from ..runtime.client import RuntimeClient
from ..runtime.config import get_runtime_env_vars
from ..runtime.models import (
    AgentRuntimeAutoscaling,
    AgentRuntimeEndpointCreateRequest,
    AgentRuntimeUpdateRequest,
)
from ..runtime.utils import build_update_body_from_runtime

logger = logging.getLogger("greennode_agentbase.cli.runtime")
configure_logger(logger)

console = Console()


@click.group(name="runtime", context_settings=CONTEXT_SETTINGS)
def runtime_group() -> None:
    """Manage runtimes and runtime endpoints.

    This command group provides operations for listing, getting, patching
    agent runtimes and managing their endpoints.
    """
    pass


def get_runtime_client() -> RuntimeClient:
    """Get a configured RuntimeClient instance.

    Returns:
        RuntimeClient instance with IAM credentials
    """
    try:
        iam_credentials = IAMCredentials()
        return RuntimeClient(iam_credentials=iam_credentials)
    except Exception as e:
        console.print(f"[red]Error: Failed to initialize runtime client: {e}[/red]")
        raise click.Abort()


@runtime_group.command(name="list")
def list_runtimes() -> None:
    """List agent runtimes.

    Prompts for page and size (defaults 1, 10).

    Examples:
        greennode runtime list
    """
    page_s = prompt_field("Page", default="1")
    _ensure_not_cancelled(page_s, "page")
    size_s = prompt_field("Size", default="10")
    _ensure_not_cancelled(size_s, "size")
    try:
        page = int(page_s)
        size = int(size_s)
    except ValueError:
        console.print("[red]Error: page and size must be integers.[/red]")
        raise click.Abort()
    try:
        client = get_runtime_client()
        result = run_async_with_cleanup(client, client.list_async(page=page, size=size))
        table = Table(title="Runtimes")
        table.add_column("ID", style="cyan")
        table.add_column("Name", style="magenta")
        table.add_column("Status", style="yellow")
        table.add_column("Created At", style="blue")
        if result.listData:
            for rt in result.listData:
                table.add_row(
                    rt.id or "",
                    rt.name or "",
                    rt.status or "",
                    str(rt.created_at) if getattr(rt, "created_at", None) else "",
                )
        console.print(table)
        if getattr(result, "totalPage", None) is not None:
            console.print(
                f"\n[dim]Page {getattr(result, 'page', 1)} of {result.totalPage} "
                f"(Total: {getattr(result, 'totalItem', '')})[/dim]"
            )
    except Exception as e:
        console.print(f"[red]Error: Failed to list runtimes: {e}[/red]")
        raise click.Abort()


@runtime_group.command(name="get")
@click.argument("runtime-id", required=False, default=None)
def get_runtime(runtime_id: Optional[str]) -> None:
    """Get a runtime by ID.

    Examples:
        greennode runtime get my-runtime-id
        greennode runtime get   # interactive mode
    """
    runtime_id = prompt_if_missing(runtime_id, "Runtime ID")
    _ensure_not_cancelled(runtime_id, "runtime_id")
    try:
        client = get_runtime_client()
        result = run_async_with_cleanup(client, client.get_async(id=runtime_id))
        if hasattr(result, "model_dump"):
            console.print(json.dumps(result.model_dump(by_alias=True), indent=2, default=str))
        elif isinstance(result, dict):
            console.print(json.dumps(result, indent=2, default=str))
        else:
            console.print(result)
    except Exception as e:
        console.print(f"[red]Error: Failed to get runtime: {e}[/red]")
        raise click.Abort()


def _parse_env_vars(env: List[str]) -> Dict[str, str]:
    """Parse KEY=value list into a dict."""
    out: Dict[str, str] = {}
    for item in env:
        if "=" in item:
            k, _, v = item.partition("=")
            out[k.strip()] = v.strip()
    return out


def _update_body_from_current(current: Any) -> Dict[str, Any]:
    """Build full update body from current runtime (DTO) and config file.
    
    Ensures all required fields are set to match backend @NotNull requirements.
    """
    body = build_update_body_from_runtime(current)
    
    # Ensure environment_variables is always a dict (required field)
    if not body.get("environment_variables"):
        config_env = get_runtime_env_vars()
        if config_env:
            body["environment_variables"] = config_env
        else:
            body["environment_variables"] = {}
    
    # Ensure command is always a list (required field)
    if "command" not in body or body["command"] is None:
        body["command"] = []
    
    # Ensure args is always a list (required field)
    if "args" not in body or body["args"] is None:
        body["args"] = []
    
    # Ensure flavor_id is set (required field)
    if not body.get("flavor_id"):
        flavor_from_config = get_config_value("GREENNODE_FLAVOR_ID") or get_config_value("flavor_id")
        if flavor_from_config:
            body["flavor_id"] = flavor_from_config
        else:
            # If still missing, try to get it from current runtime
            if hasattr(current, "flavor_id") and current.flavor_id:
                body["flavor_id"] = current.flavor_id
            elif isinstance(current, dict) and (current.get("flavorId") or current.get("flavor_id")):
                body["flavor_id"] = current.get("flavorId") or current.get("flavor_id")
    
    # Ensure description is set (required field)
    if "description" not in body or body["description"] is None:
        # Try to get from current runtime
        if hasattr(current, "description") and current.description is not None:
            body["description"] = current.description
        elif isinstance(current, dict) and current.get("description") is not None:
            body["description"] = current.get("description")
        else:
            body["description"] = ""
    
    # Ensure autoscaling is set (required field)
    if "autoscaling" not in body or body["autoscaling"] is None:
        body["autoscaling"] = AgentRuntimeAutoscaling()
    
    # Ensure image_url is set (required field) - get from current if not already set
    if not body.get("image_url"):
        if hasattr(current, "image_url") and current.image_url:
            body["image_url"] = current.image_url
        elif isinstance(current, dict) and (current.get("imageUrl") or current.get("image_url")):
            body["image_url"] = current.get("imageUrl") or current.get("image_url")
    
    return body


@runtime_group.command(name="patch")
@click.argument("runtime-id", required=False, default=None)
@click.option("--image-url", type=str, help="Image URL to set")
@click.option("--flavor-id", type=str, help="Flavor ID to set")
@click.option("--command", type=str, multiple=True, help="Command (repeat for multiple)")
@click.option("--args", "args_list", type=str, multiple=True, help="Args (repeat for multiple)")
@click.option("--env", "env_vars", type=str, multiple=True, help="Env var KEY=value (repeat for multiple)")
def patch_runtime(
    runtime_id: Optional[str],
    image_url: Optional[str],
    flavor_id: Optional[str],
    command: tuple,
    args_list: tuple,
    env_vars: tuple,
) -> None:
    """Update (patch) a runtime by ID.

    Sends a full update payload: current runtime state from GET, filled from
    config file where missing, then overridden by CLI options.

    Examples:
        greennode runtime patch my-runtime-id --image-url my-registry/my-image:tag
        greennode runtime patch my-runtime-id --flavor-id new-flavor --env FOO=bar
        greennode runtime patch   # interactive mode
    """
    runtime_id = prompt_if_missing(runtime_id, "Runtime ID")
    _ensure_not_cancelled(runtime_id, "runtime_id")
    if not any([image_url is not None, flavor_id is not None, command, args_list, env_vars]):
        console.print("[yellow]No updates specified. Use --image-url, --flavor-id, --command, --args, or --env.[/yellow]")
        return
    try:
        client = get_runtime_client()
        current = run_async_with_cleanup(client, client.get_async(id=runtime_id))
        body = _update_body_from_current(current)
        if image_url is not None:
            body["image_url"] = image_url
        if flavor_id is not None:
            body["flavor_id"] = flavor_id
        if command:
            body["command"] = list(command)
        if args_list:
            body["args"] = list(args_list)
        if env_vars:
            body["environment_variables"] = _parse_env_vars(list(env_vars))
        request = AgentRuntimeUpdateRequest(**body)
        result = run_async_with_cleanup(client, client.update_async(id=runtime_id, request=request))
        if hasattr(result, "model_dump"):
            console.print(json.dumps(result.model_dump(by_alias=True), indent=2, default=str))
        elif isinstance(result, dict):
            console.print(json.dumps(result, indent=2, default=str))
        else:
            console.print(result)
        console.print(f"[green]✓ Runtime {runtime_id} updated[/green]")
    except Exception as e:
        console.print(f"[red]Error: Failed to patch runtime: {e}[/red]")
        raise click.Abort()


