@runtime_group.group(name="endpoints")
def endpoints_group() -> None:
    """Manage runtime endpoints."""
    pass


@endpoints_group.command(name="list")
@click.argument("runtime-id", required=False, default=None)
def list_endpoints(runtime_id: Optional[str]) -> None:
    """List endpoints for a runtime.

    Examples:
        greennode runtime endpoints list my-runtime-id
        greennode runtime endpoints list   # interactive mode
    """
    runtime_id = prompt_if_missing(runtime_id, "Runtime ID")
    _ensure_not_cancelled(runtime_id, "runtime_id")
    page_s = prompt_field("Page", default="1")
    _ensure_not_cancelled(page_s, "page")
    size_s = prompt_field("Size", default="10")
    _ensure_not_cancelled(size_s, "size")
    try:
        page = int(page_s)
        size = int(size_s)
    except ValueError:
        console.print("[red]Error: page and size must be integers.[/red]")
        raise click.Abort()
    try:
        client = get_runtime_client()
        result = run_async_with_cleanup(client, client.list_endpoints_async(id=runtime_id, page=page, size=size))
        table = Table(title=f"Endpoints for runtime {runtime_id}")
        table.add_column("ID", style="cyan")
        table.add_column("Name", style="magenta")
        table.add_column("Version", style="yellow")
        table.add_column("URL", style="green")
        table.add_column("Status", style="blue")
        if result.listData:
            for ep in result.listData:
                table.add_row(
                    ep.id or "",
                    ep.name or "",
                    str(ep.version) if ep.version is not None else "",
                    ep.url or "",
                    ep.status or "",
                )
        console.print(table)
    except Exception as e:
        console.print(f"[red]Error: Failed to list endpoints: {e}[/red]")
        raise click.Abort()


@endpoints_group.command(name="create")
@click.argument("runtime-id", required=False, default=None)
@click.option("--name", "-n", required=False, default=None, help="Endpoint name")
@click.option("--version", "-v", type=int, help="Version (optional)")
def create_endpoint(runtime_id: Optional[str], name: Optional[str], version: Optional[int]) -> None:
    """Create an endpoint for a runtime.

    Examples:
        greennode runtime endpoints create my-runtime-id -n my-endpoint
        greennode runtime endpoints create my-runtime-id -n my-endpoint --version 1
        greennode runtime endpoints create   # interactive mode
    """
    runtime_id = prompt_if_missing(runtime_id, "Runtime ID")
    _ensure_not_cancelled(runtime_id, "runtime_id")
    name = prompt_if_missing(name, "Endpoint name")
    _ensure_not_cancelled(name, "name")
    try:
        client = get_runtime_client()
        request = AgentRuntimeEndpointCreateRequest(name=name, version=version)
        result = run_async_with_cleanup(client, client.create_endpoint_async(id=runtime_id, request=request))
        if hasattr(result, "id"):
            console.print(f"[green]✓ Endpoint created with id: {result.id}[/green]")
        else:
            out = result if isinstance(result, dict) else str(result)
            console.print(json.dumps(out, indent=2) if isinstance(out, dict) else out)
    except Exception as e:
        console.print(f"[red]Error: Failed to create endpoint: {e}[/red]")
        raise click.Abort()


